  "gateway": {
    "extensions": {
      "defaults": {
        "botnexus-skills": { "enabled": true, "maxLoadedSkills": 20 },
        "botnexus-exec": { "enabled": true }
      }
    }
  },
  "agents": {
    "nova": {
      "extensions": {
        "botnexus-skills": { "maxLoadedSkills": 30 }
      }
    },
